def test_ach_transfer_at_exact_limit_boundary_is_accepted(ach_client, verified_ach_account, funded_customer_token):
    payload = {
        "amount": 10000,
        "currency": "USD",
        "destination_account_id": verified_ach_account["id"]
    }
    resp = ach_client.post(
        "/transfers/ach",
        json=payload,
        headers={"Authorization": f"Bearer {funded_customer_token}"}
    )
    assert resp.status_code == 202
    body = resp.json()
    assert "transfer_id" in body
    assert body["status"] == "queued"
    assert "error_code" not in body

def test_ach_transfer_one_cent_above_limit_without_step_up_returns_422(ach_client, verified_ach_account, funded_customer_token):
    payload = {
        "amount": 10000.01,
        "currency": "USD",
        "destination_account_id": verified_ach_account["id"]
    }
    resp = ach_client.post(
        "/transfers/ach",
        json=payload,
        headers={"Authorization": f"Bearer {funded_customer_token}"}
    )
    assert resp.status_code == 422
    body = resp.json()
    assert body.get("error_code") == "STEP_UP_REQUIRED"
    assert "transfer_id" not in body

