def test_ach_transfer_above_limit_with_step_up_transitions_to_queued(ach_client, verified_ach_account, funded_customer_token):
    step_up_token = <get_step_up_token>(funded_customer_token)
    payload = {
        "amount": 15000,
        "currency": "USD",
        "destination_account_id": verified_ach_account["id"]
    }
    resp = ach_client.post(
        "/transfers/ach",
        json=payload,
        headers={
            "Authorization": f"Bearer {funded_customer_token}",
            "X-Step-Up-Token": step_up_token
        }
    )
    assert resp.status_code == 202
    body = resp.json()
    assert "transfer_id" in body
    assert body["status"] == "queued"
